// frontend/src/components/LeanConnect.tsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:3001';

declare global {
    interface Window {
        Lean: any;
    }
}

interface LeanConnectProps {
    customerId: string;
    onConsentCreated: (consentId: string) => void;
    onSuccess: (entityId: string) => void;
    onError: (error: string) => void;
}

const LeanConnect: React.FC<LeanConnectProps> = ({ customerId, onConsentCreated, onSuccess, onError }) => {
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<string>('');
    const [consentId, setConsentId] = useState<string | null>(null);
    const callbackRegistered = useRef(false);

    // Register the Lean callback once
    useEffect(() => {
        if (!callbackRegistered.current && window.Lean) {
            console.log('🔄 Registering Lean callback...');
            window.Lean.callback = (response: any) => {
                console.log('📨 Lean callback received:', response);
                setLoading(false);
                if (response.status === 'SUCCESS') {
                    setStatus('✅ Consent authorized successfully!');
                    onSuccess(response.entity_id || 'success');
                } else if (response.status === 'ERROR') {
                    setStatus('❌ Error: ' + response.message);
                    onError(response.message || 'Failed');
                } else if (response.status === 'CANCEL') {
                    setStatus('⏹️ Cancelled');
                    onError('Cancelled');
                }
            };
            callbackRegistered.current = true;
        }
    }, []);

    // Step 1: Create Consent
    const handleCreateConsent = async () => {
        setLoading(true);
        setStatus('📝 Creating consent...');

        try {
            const response = await axios.post(`${API_URL}/api/lean/create-consent`, {
                customerId
            });

            if (!response.data.success) {
                throw new Error(response.data.error || 'Consent creation failed');
            }

            const newConsentId = response.data.consentId;
            setConsentId(newConsentId);
            onConsentCreated(newConsentId);
            setStatus(`✅ Consent created: ${newConsentId}. Now authorizing...`);

            // Step 2: Authorize the consent
            await handleAuthorizeConsent(newConsentId);

        } catch (error: any) {
            setStatus('❌ Error: ' + error.message);
            onError(error.message);
            setLoading(false);
        }
    };

    // Step 2: Authorize Consent
    const handleAuthorizeConsent = async (consentId: string) => {
        try {
            // Get customer-scoped token
            const tokenRes = await axios.get(`${API_URL}/api/lean/customer-token`, {
                params: { customerId }
            });

            if (!tokenRes.data.success) {
                throw new Error(tokenRes.data.error || 'Customer token failed');
            }

            const customerToken = tokenRes.data.customerToken;
            const appToken = '730a9f67-7149-49e5-988d-30200b8fa695';

            // Call Lean.connect() with the consent_id
            window.Lean.connect({
                access_token: customerToken,
                app_token: appToken,
                customer_id: customerId,
                consent_id: consentId,
                sandbox: true,
                debug: true
            });

            setStatus('🔄 Waiting for bank authorization...');
            console.log('✅ Lean.connect() called for consent authorization');

        } catch (error: any) {
            setStatus('❌ Authorization error: ' + error.message);
            onError(error.message);
            setLoading(false);
        }
    };

    const handleConnect = async () => {
        // If we already have a consentId, just authorize it
        if (consentId) {
            await handleAuthorizeConsent(consentId);
            return;
        }
        // Otherwise create consent first
        await handleCreateConsent();
    };

    return (
        <div className="lean-connect">
            <button
                onClick={handleConnect}
                disabled={loading}
                className="btn-connect"
                style={{
                    width: '100%',
                    padding: '12px',
                    background: loading ? '#a0aec0' : 'linear-gradient(135deg, #006a4e, #00875a)',
                    color: '#fff',
                    border: 'none',
                    borderRadius: '10px',
                    fontSize: '16px',
                    fontWeight: '600',
                    cursor: loading ? 'not-allowed' : 'pointer',
                }}
            >
                {loading ? '⏳ Connecting...' : '🔗 Connect Bank Account'}
            </button>

            {status && (
                <p style={{ marginTop: 8, fontSize: 13, color: status.includes('✅') ? '#22543d' : '#9b2c2c' }}>
                    {status}
                </p>
            )}

            {consentId && (
                <p style={{ marginTop: 4, fontSize: 12, color: '#2b6cb0' }}>
                    Consent ID: {consentId}
                </p>
            )}

            {loading && (
                <button
                    onClick={() => {
                        setStatus('⏹️ Cancelled by user');
                        setLoading(false);
                        onError('Cancelled');
                    }}
                    style={{
                        marginTop: 8,
                        padding: '8px 16px',
                        background: '#e53e3e',
                        color: '#fff',
                        border: 'none',
                        borderRadius: '6px',
                        cursor: 'pointer',
                        fontSize: '13px'
                    }}
                >
                    Cancel
                </button>
            )}
        </div>
    );
};

export default LeanConnect;
